import type { Config } from 'tailwindcss'

const config: Config = {
  darkMode: ['class'],
  content: [
    './pages/**/*.{js,ts,jsx,tsx,mdx}',
    './components/**/*.{js,ts,jsx,tsx,mdx}',
    './app/**/*.{js,ts,jsx,tsx,mdx}',
    '*.{js,ts,jsx,tsx,mdx}',
  ],
  theme: {
    extend: {
      fontFamily: {
        sans: ['var(--font-plus-jakarta)', 'system-ui', 'sans-serif'],
      },
      colors: {
        background: 'hsl(var(--background))',
        foreground: 'hsl(var(--foreground))',
        card: {
          DEFAULT: 'hsl(var(--card))',
          foreground: 'hsl(var(--card-foreground))',
        },
        popover: {
          DEFAULT: 'hsl(var(--popover))',
          foreground: 'hsl(var(--popover-foreground))',
        },
        primary: {
          DEFAULT: 'hsl(var(--primary))',
          foreground: 'hsl(var(--primary-foreground))',
        },
        secondary: {
          DEFAULT: 'hsl(var(--secondary))',
          foreground: 'hsl(var(--secondary-foreground))',
        },
        muted: {
          DEFAULT: 'hsl(var(--muted))',
          foreground: 'hsl(var(--muted-foreground))',
        },
        accent: {
          DEFAULT: 'hsl(var(--accent))',
          foreground: 'hsl(var(--accent-foreground))',
        },
        destructive: {
          DEFAULT: 'hsl(var(--destructive))',
          foreground: 'hsl(var(--destructive-foreground))',
        },
        border: 'hsl(var(--border))',
        input: 'hsl(var(--input))',
        ring: 'hsl(var(--ring))',
      },
      keyframes: {
        'collapsible-down': {
          from: { height: '0', opacity: '0' },
          to: { height: 'var(--radix-collapsible-content-height)', opacity: '1' },
        },
        'collapsible-up': {
          from: { height: 'var(--radix-collapsible-content-height)', opacity: '1' },
          to: { height: '0', opacity: '0' },
        },
      },
      animation: {
        'collapsible-down': 'collapsible-down 0.2s ease-out',
        'collapsible-up':   'collapsible-up 0.2s ease-out',
      },
      borderRadius: {
        lg: 'var(--radius)',
        md: 'calc(var(--radius) - 2px)',
        sm: 'calc(var(--radius) - 4px)',
      },
    },
  },
  plugins: [require('tailwindcss-animate')],
}
export default config

/**
 * AdminTable — Componente de tabela global do painel administrativo
 *
 * REUSO OBRIGATÓRIO: Este componente JÁ EXISTE e deve ser usado em TODAS as
 * tabelas do painel admin. NÃO construa tabelas manuais com grid/flex.
 * Baseado em @tanstack/react-table + shadcn/ui table.
 *
 * Props:
 *   data: TData[]                   — array de dados a exibir
 *   columns: ColumnDef<TData>[]     — definição de colunas (TanStack format)
 *   filterValue?: string            — valor externo de filtro global (busca)
 *   onFilterChange?: (v: string)    — callback ao alterar busca interna
 *   searchPlaceholder?: string      — placeholder do campo de busca
 *   showSearch?: boolean            — exibe campo de busca (padrão: true)
 *   pageSize?: number               — linhas por página (padrão: 10)
 *   emptyMessage?: string           — mensagem quando não há dados
 *   emptyIcon?: React.ReactNode     — ícone do estado vazio
 *   loading?: boolean               — exibe skeleton de carregamento
 *   className?: string              — classe extra no container
 *
 * Uso básico:
 *   import { AdminTable } from "@/components/admin/admin-table"
 *   import { ColumnDef } from "@tanstack/react-table"
 *
 *   const columns: ColumnDef<Meu Tipo>[] = [
 *     { accessorKey: "nome",   header: "Nome"   },
 *     { accessorKey: "status", header: "Status" },
 *     {
 *       id: "acoes",
 *       header: "",
 *       cell: ({ row }) => <BotaoAcao row={row.original} />,
 *     },
 *   ]
 *
 *   <AdminTable data={dados} columns={columns} searchPlaceholder="Buscar..." />
 *
 * Coluna com ordenação:
 *   { accessorKey: "nome", header: ({ column }) => (
 *     <AdminTableSortHeader column={column} label="Nome" />
 *   )}
 *
 * Passando filtro externo (busca controlada fora do componente):
 *   <AdminTable data={dados} columns={columns} filterValue={busca} />
 */

"use client"

import * as React from "react"
import {
  ColumnDef,
  ColumnFiltersState,
  SortingState,
  flexRender,
  getCoreRowModel,
  getFilteredRowModel,
  getPaginationRowModel,
  getSortedRowModel,
  useReactTable,
  Column,
} from "@tanstack/react-table"
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table"
import { Skeleton } from "@/components/ui/skeleton"
import { AdminButton } from "@/components/admin/admin-button"
import { AdminInput } from "@/components/admin/admin-input"
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select"
import { ArrowUpDown, ArrowUp, ArrowDown, Search, TableIcon } from "lucide-react"
import {
  Pagination,
  PaginationContent,
  PaginationItem,
  PaginationLink,
  PaginationNext,
  PaginationPrevious,
} from "@/components/ui/pagination"
import { cn } from "@/lib/utils"

// ─── AdminTableSortHeader ─────────────────────────────────────────────────────
interface AdminTableSortHeaderProps<TData> {
  column: Column<TData, unknown>
  label: string
}

export function AdminTableSortHeader<TData>({ column, label }: AdminTableSortHeaderProps<TData>) {
  const sorted = column.getIsSorted()
  return (
    <button
      className="flex items-center gap-1.5 text-xs font-semibold text-gray-500 uppercase tracking-wide hover:text-gray-700 transition-colors"
      onClick={() => column.toggleSorting(sorted === "asc")}
    >
      {label}
      {sorted === "asc"  ? <ArrowUp size={13} />   :
       sorted === "desc" ? <ArrowDown size={13} />  :
       <ArrowUpDown size={13} className="opacity-40" />}
    </button>
  )
}

// ─── AdminTable ───────────────────────────────────────────────────────────────
interface AdminTableProps<TData> {
  data: TData[]
  columns: ColumnDef<TData, unknown>[]
  filterValue?: string
  onFilterChange?: (value: string) => void
  searchPlaceholder?: string
  showSearch?: boolean
  pageSize?: number
  emptyMessage?: string
  emptyIcon?: React.ReactNode
  loading?: boolean
  className?: string
}

export function AdminTable<TData>({
  data,
  columns,
  filterValue,
  onFilterChange,
  searchPlaceholder = "Buscar…",
  showSearch = true,
  pageSize = 10,
  emptyMessage = "Nenhum resultado encontrado.",
  emptyIcon,
  loading = false,
  className,
}: AdminTableProps<TData>) {
  const [sorting, setSorting] = React.useState<SortingState>([])
  const [columnFilters, setColumnFilters] = React.useState<ColumnFiltersState>([])
  const [globalFilter, setGlobalFilter] = React.useState(filterValue ?? "")

  // Sincroniza filtro externo → interno
  React.useEffect(() => {
    if (filterValue !== undefined) setGlobalFilter(filterValue)
  }, [filterValue])

  const table = useReactTable({
    data,
    columns,
    state: { sorting, columnFilters, globalFilter },
    onSortingChange: setSorting,
    onColumnFiltersChange: setColumnFilters,
    onGlobalFilterChange: setGlobalFilter,
    getCoreRowModel: getCoreRowModel(),
    getSortedRowModel: getSortedRowModel(),
    getFilteredRowModel: getFilteredRowModel(),
    getPaginationRowModel: getPaginationRowModel(),
    initialState: { pagination: { pageSize } },
  })

  const totalPages = table.getPageCount()
  const currentPage = table.getState().pagination.pageIndex + 1

  if (loading) {
    return (
      <div className={cn("space-y-4", className)}>
        {showSearch && <Skeleton className="h-10 w-full rounded-lg" />}
        <div className="bg-white rounded-2xl border border-gray-100 shadow-sm overflow-hidden">
          <div className="border-b border-gray-100 bg-gray-50 px-4 py-3 flex gap-6">
            {columns.map((_, i) => <Skeleton key={i} className="h-4 w-24 rounded" />)}
          </div>
          {Array.from({ length: pageSize > 5 ? 5 : pageSize }).map((_, i) => (
            <div key={i} className="flex gap-6 px-4 py-4 border-b border-gray-50">
              {columns.map((_, j) => <Skeleton key={j} className="h-4 rounded" style={{ width: `${60 + j * 20}px` }} />)}
            </div>
          ))}
        </div>
      </div>
    )
  }

  return (
    <div className={cn("space-y-4", className)}>
      {/* Busca interna */}
      {showSearch && filterValue === undefined && (
        <AdminInput
          variant="form"
          placeholder={searchPlaceholder}
          value={globalFilter}
          onChange={(e) => {
            setGlobalFilter(e.target.value)
            onFilterChange?.(e.target.value)
          }}
          icon={<Search size={15} />}
        />
      )}

      {/* Tabela */}
      <div className="bg-white rounded-2xl border border-gray-100 shadow-sm overflow-hidden">
        <Table>
          <TableHeader>
            {table.getHeaderGroups().map((hg) => (
              <TableRow key={hg.id} className="bg-gray-50 hover:bg-gray-50 border-b border-gray-100">
                {hg.headers.map((header) => (
                  <TableHead
                    key={header.id}
                    className="px-4 py-3 text-xs font-semibold text-gray-500 uppercase tracking-wide h-auto"
                  >
                    {header.isPlaceholder
                      ? null
                      : flexRender(header.column.columnDef.header, header.getContext())}
                  </TableHead>
                ))}
              </TableRow>
            ))}
          </TableHeader>
          <TableBody>
            {table.getRowModel().rows.length === 0 ? (
              <TableRow className="hover:bg-transparent">
                <TableCell colSpan={columns.length} className="py-16">
                  <div className="flex flex-col items-center gap-2 text-gray-400">
                    {emptyIcon ?? <TableIcon size={32} className="opacity-30" />}
                    <p className="text-sm">{emptyMessage}</p>
                  </div>
                </TableCell>
              </TableRow>
            ) : (
              table.getRowModel().rows.map((row) => (
                <TableRow
                  key={row.id}
                  className="border-b border-gray-50 hover:bg-gray-50/60 transition-colors"
                >
                  {row.getVisibleCells().map((cell) => (
                    <TableCell key={cell.id} className="px-4 py-3 align-middle">
                      {flexRender(cell.column.columnDef.cell, cell.getContext())}
                    </TableCell>
                  ))}
                </TableRow>
              ))
            )}
          </TableBody>
        </Table>
      </div>

      {/* Paginação */}
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-2">
          <span className="text-xs font-medium text-gray-600">Itens por página</span>
          <Select
            value={String(table.getState().pagination.pageSize)}
            onValueChange={(v) => {
              table.setPageSize(Number(v))
              table.setPageIndex(0)
            }}
          >
            <SelectTrigger className="h-8 w-16 px-2 text-xs">
              <SelectValue placeholder={String(table.getState().pagination.pageSize)} />
            </SelectTrigger>
            <SelectContent position="popper" side="bottom" sideOffset={4}>
              {[5, 10, 20, 50].map((size) => (
                <SelectItem key={size} value={String(size)}>{size}</SelectItem>
              ))}
            </SelectContent>
          </Select>
        </div>
        <Pagination className="w-auto mx-0">
          <PaginationContent>
            <PaginationItem>
              <PaginationPrevious
                onClick={() => table.previousPage()}
                disabled={!table.getCanPreviousPage()}
                className={!table.getCanPreviousPage() ? "opacity-50 cursor-not-allowed" : "cursor-pointer"}
              />
            </PaginationItem>
            {Array.from({ length: totalPages }).map((_, i) => (
              <PaginationItem key={i + 1}>
                <PaginationLink
                  onClick={() => table.setPageIndex(i)}
                  isActive={currentPage === i + 1}
                  size="sm"
                  className={cn(
                    "h-8 w-8 text-xs cursor-pointer rounded-lg",
                    currentPage === i + 1 && "bg-[#0B7A8F] text-white border-[#0B7A8F] hover:bg-[#0B7A8F] hover:text-white"
                  )}
                >
                  {i + 1}
                </PaginationLink>
              </PaginationItem>
            ))}
            <PaginationItem>
              <PaginationNext
                onClick={() => table.nextPage()}
                disabled={!table.getCanNextPage()}
                className={!table.getCanNextPage() ? "opacity-50 cursor-not-allowed" : "cursor-pointer"}
              />
            </PaginationItem>
          </PaginationContent>
        </Pagination>
      </div>
    </div>
  )
}

"use client"

import { useMemo, useState } from "react"
import Link from "next/link"
import { AdminDashboardLayout } from "@/components/admin/admin-dashboard-layout"
import { AdminButton } from "@/components/admin/admin-button"
import { AdminTable } from "@/components/admin/admin-table"
import { AdminModal, AdminModalHeader, AdminModalBody, AdminModalFooter } from "@/components/admin/admin-modal"
import { AdminInput } from "@/components/admin/admin-input"
import { vistorias, type Vistoria } from "@/lib/mock-vistorias"
import { type ColumnDef } from "@tanstack/react-table"
import { Eye, Plus, CheckCircle2, Copy, MapPin, FileText, Calendar, Search } from "lucide-react"
import { RadioGroup, RadioGroupItem } from "@/components/ui/radio-group"
import { Label } from "@/components/ui/label"
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select"

const TIPOS_VISTORIA = ["Entrada", "Saída", "Conferência", "Rescisão"] as const

function gerarCodigo() {
  const ano = new Date().getFullYear()
  const num = Math.floor(1000 + Math.random() * 9000)
  return `V-${ano}-${num}`
}

const columns: ColumnDef<Vistoria, unknown>[] = [
  {
    accessorKey: "id",
    header: "Código",
    cell: ({ row }) => (
      <span className="font-mono text-xs text-gray-500">{row.original.id}</span>
    ),
  },
  {
    accessorKey: "endereco",
    header: "Endereço",
    cell: ({ row }) => (
      <span className="text-sm text-gray-700">{row.original.endereco}</span>
    ),
  },
  {
    accessorKey: "tipo",
    header: "Tipo",
    cell: ({ row }) => (
      <span className="text-sm text-gray-500">{row.original.tipo}</span>
    ),
  },
  {
    id: "status",
    header: "Status",
    cell: () => (
      <span className="px-2.5 py-1 rounded-full text-xs font-semibold text-yellow-700 bg-yellow-50">
        Aguardando
      </span>
    ),
  },
  {
    id: "acoes",
    header: "",
    cell: ({ row }) => (
      <Link href={`/admin/cliente/vistorias/${row.original.id}`}>
        <AdminButton variant="ghost" size="sm" icon={<Eye size={14} />} className="h-8 w-8 p-0" title="Ver" />
      </Link>
    ),
  },
]

export default function VistoriasPedidosPage() {
  const data = useMemo(() => vistorias.filter((v) => v.status === "Pedido"), [])
  const [searchValue, setSearchValue] = useState("")

  // Modal
  const [showModal, setShowModal] = useState(false)
  const [etapa, setEtapa] = useState<"formulario" | "sucesso">("formulario")
  const [codigoGerado, setCodigoGerado] = useState("")
  const [copiado, setCopiado] = useState(false)

  // Campos
  const [endereco, setEndereco] = useState("")
  const [complemento, setComplemento] = useState("")
  const [cidade, setCidade] = useState("")
  const [tipo, setTipo] = useState("")
  const [dataVistoria, setDataVistoria] = useState("")
  const [hora, setHora] = useState("")
  const [obs, setObs] = useState("")

  const formValido = !!(endereco && cidade && tipo && dataVistoria && hora)

  function abrirModal() {
    setEtapa("formulario")
    setCodigoGerado("")
    setEndereco(""); setComplemento(""); setCidade("")
    setTipo(""); setDataVistoria(""); setHora(""); setObs("")
    setShowModal(true)
  }

  function solicitar() {
    setCodigoGerado(gerarCodigo())
    setEtapa("sucesso")
  }

  function copiarCodigo() {
    navigator.clipboard.writeText(codigoGerado)
    setCopiado(true)
    setTimeout(() => setCopiado(false), 2000)
  }

  return (
    <AdminDashboardLayout
      profile="cliente"
      title="Vistorias Solicitadas"
      breadcrumbs={[{ label: "Vistorias", href: "/admin/cliente/vistorias/pedidos" }]}
    >
      <div className="space-y-4">
        {/* Busca + Novo Pedido na mesma linha */}
        <div className="flex flex-wrap items-end gap-3">
          <div className="flex-1 min-w-[250px]">
            <AdminInput
              variant="form"
              placeholder="Buscar por código ou endereço..."
              value={searchValue}
              onChange={(e) => setSearchValue(e.target.value)}
              icon={<Search size={15} />}
            />
          </div>
          <div>
            <AdminButton variant="primary" icon={<Plus size={16} />} onClick={abrirModal}>
              Nova Vistoria
            </AdminButton>
          </div>
        </div>

        {/* Tabela sem search interno */}
        <AdminTable
          data={data}
          columns={columns}
          filterValue={searchValue}
          onFilterChange={setSearchValue}
          showSearch={false}
          emptyMessage="Nenhuma vistoria solicitada aguardando agendamento."
        />
      </div>

      {showModal && (
        <AdminModal onClose={() => setShowModal(false)} size="sm">
          {etapa === "formulario" ? (
            <>
              <AdminModalHeader
                title="Solicitar Nova Vistoria"
                subtitle="Preencha os dados para registrar sua solicitação"
                onClose={() => setShowModal(false)}
              />
              <AdminModalBody>
                {/* Endereço */}
                <div className="space-y-3">
                  <p className="text-xs font-semibold text-gray-500 flex items-center gap-1.5 uppercase tracking-wide">
                    <MapPin size={13} className="text-[#0B7A8F]" /> Endereço do Imóvel
                  </p>
                  <AdminInput
                    variant="form"
                    label="Endereço"
                    placeholder="Rua, número..."
                    value={endereco}
                    onChange={(e) => setEndereco(e.target.value)}
                  />
                  <AdminInput
                    variant="form"
                    label="Complemento"
                    placeholder="Apto, bloco... (opcional)"
                    value={complemento}
                    onChange={(e) => setComplemento(e.target.value)}
                  />
                  <AdminInput
                    variant="form"
                    label="Cidade / UF"
                    placeholder="São Paulo, SP"
                    value={cidade}
                    onChange={(e) => setCidade(e.target.value)}
                  />
                </div>

                {/* Tipo */}
                <div className="space-y-3">
                  <p className="text-xs font-semibold text-gray-500 flex items-center gap-1.5 uppercase tracking-wide">
                    <FileText size={13} className="text-[#0B7A8F]" /> Tipo de Vistoria
                  </p>
                  <RadioGroup value={tipo} onValueChange={setTipo} className="grid grid-cols-2 gap-2">
                    {TIPOS_VISTORIA.map((t) => (
                      <div
                        key={t}
                        className={`flex items-center gap-2 p-3 border rounded-xl cursor-pointer transition-colors ${
                          tipo === t ? "border-[#0B7A8F] bg-[#0B7A8F]/5" : "border-gray-200 hover:border-gray-300"
                        }`}
                      >
                        <RadioGroupItem value={t} id={`tipo-${t}`} />
                        <Label htmlFor={`tipo-${t}`} className="cursor-pointer text-sm">{t}</Label>
                      </div>
                    ))}
                  </RadioGroup>
                </div>

                {/* Data e Hora */}
                <div className="space-y-3">
                  <p className="text-xs font-semibold text-gray-500 flex items-center gap-1.5 uppercase tracking-wide">
                    <Calendar size={13} className="text-[#0B7A8F]" /> Data e Hora Desejada
                  </p>
                  <div className="grid grid-cols-2 gap-3">
                    <AdminInput
                      variant="form"
                      label="Data"
                      type="date"
                      value={dataVistoria}
                      onChange={(e) => setDataVistoria(e.target.value)}
                    />
                    <div className="space-y-1.5">
                      <label className="text-sm font-medium text-gray-700">Horário</label>
                      <Select value={hora} onValueChange={setHora}>
                        <SelectTrigger className="h-10">
                          <SelectValue placeholder="Selecione" />
                        </SelectTrigger>
                        <SelectContent>
                          {["08:00","09:00","10:00","11:00","13:00","14:00","15:00","16:00","17:00"].map((h) => (
                            <SelectItem key={h} value={h}>{h}</SelectItem>
                          ))}
                        </SelectContent>
                      </Select>
                    </div>
                  </div>
                </div>

                {/* Observações */}
                <div className="space-y-1.5">
                  <label className="text-sm font-medium text-gray-700">Observações (opcional)</label>
                  <textarea
                    className="w-full h-20 px-3 py-2 text-sm border border-gray-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-[#0B7A8F]/20 focus:border-[#0B7A8F] resize-none"
                    placeholder="Informações adicionais sobre o imóvel ou acesso..."
                    value={obs}
                    onChange={(e) => setObs(e.target.value)}
                  />
                </div>
              </AdminModalBody>
              <AdminModalFooter>
                <AdminButton variant="outline" onClick={() => setShowModal(false)}>Cancelar</AdminButton>
                <AdminButton variant="primary" onClick={solicitar} disabled={!formValido}>
                  Solicitar Vistoria
                </AdminButton>
              </AdminModalFooter>
            </>
          ) : (
            <>
              <AdminModalHeader title="Solicitação Enviada" onClose={() => setShowModal(false)} />
              <AdminModalBody>
                <div className="flex flex-col items-center text-center py-2 gap-4">
                  <div className="w-14 h-14 rounded-full bg-emerald-100 flex items-center justify-center">
                    <CheckCircle2 size={28} className="text-emerald-600" />
                  </div>
                  <div>
                    <h3 className="text-base font-semibold text-gray-900">Vistoria solicitada com sucesso!</h3>
                    <p className="text-sm text-gray-500 mt-1">Em breve entraremos em contato para confirmar o agendamento.</p>
                  </div>

                  {/* Código */}
                  <div className="w-full p-4 bg-gray-50 rounded-xl">
                    <p className="text-xs text-gray-500 mb-1">Código da solicitação</p>
                    <div className="flex items-center justify-center gap-2">
                      <span className="text-2xl font-bold tracking-widest text-[#0B7A8F] font-mono">{codigoGerado}</span>
                      <button
                        onClick={copiarCodigo}
                        className="p-1.5 hover:bg-gray-200 rounded-lg transition-colors"
                        title="Copiar código"
                      >
                        {copiado
                          ? <CheckCircle2 size={16} className="text-emerald-600" />
                          : <Copy size={16} className="text-gray-400" />
                        }
                      </button>
                    </div>
                  </div>

                  {/* Resumo */}
                  <div className="w-full p-4 bg-[#0B7A8F]/5 border border-[#0B7A8F]/10 rounded-xl text-left space-y-2">
                    <p className="text-sm text-gray-600">
                      <span className="text-gray-400">Endereço: </span>
                      <span className="font-medium">{endereco}{complemento ? `, ${complemento}` : ""} — {cidade}</span>
                    </p>
                    <p className="text-sm text-gray-600">
                      <span className="text-gray-400">Tipo: </span>
                      <span className="font-medium">{tipo}</span>
                    </p>
                    <p className="text-sm text-gray-600">
                      <span className="text-gray-400">Data/Hora: </span>
                      <span className="font-medium">
                        {new Date(dataVistoria + "T00:00:00").toLocaleDateString("pt-BR")} às {hora}
                      </span>
                    </p>
                  </div>
                </div>
