/**
 * AdminTabs — Componente de abas do painel administrativo
 *
 * REUSO OBRIGATÓRIO: Use este componente para navegação por abas no painel admin.
 * NÃO defina abas inline nos arquivos.
 *
 * Uso:
 *   import { AdminTabs, AdminTab } from "@/components/admin/admin-tabs"
 *
 *   const abas = [
 *     { id: "clientes",  label: "Clientes",  icon: Users },
 *     { id: "condicoes", label: "Condições", icon: Briefcase },
 *   ]
 *
 *   <AdminTabs value={aba} onChange={setAba} tabs={abas} />
 *
 *   // Ou com children para maior controle:
 *   <AdminTabs value={aba} onChange={setAba}>
 *     <AdminTab value="clientes" icon={<Users size={15} />}>Clientes</AdminTab>
 *     <AdminTab value="condicoes" icon={<Briefcase size={15} />}>Condições</AdminTab>
 *   </AdminTabs>
 */

import React from "react"
import { cn } from "@/lib/utils"

interface TabItem {
  id: string
  label: string
  icon?: React.ElementType
}

interface AdminTabsProps {
  value: string
  onChange: (value: string) => void
  tabs?: TabItem[]
  children?: React.ReactNode
  className?: string
}

export function AdminTabs({ value, onChange, tabs, children, className }: AdminTabsProps) {
  return (
    <div className={cn("flex items-center gap-1 border-b border-[rgb(229,231,235)]", className)}>
      {tabs
        ? tabs.map((tab) => {
            const Icon = tab.icon
            const active = value === tab.id
            return (
              <button
                key={tab.id}
                onClick={() => onChange(tab.id)}
                className={cn(
                  "flex items-center gap-2 px-4 py-2.5 text-sm font-medium border-b-2 transition-colors -mb-px",
                  active
                    ? "border-[#0B7A8F] text-[#0B7A8F]"
                    : "border-transparent text-gray-500 hover:text-gray-700"
                )}
              >
                {Icon && <Icon size={15} />}
                {tab.label}
              </button>
            )
          })
        : React.Children.map(children, (child) => {
            if (React.isValidElement<AdminTabProps>(child)) {
              return React.cloneElement(child, {
                active: value === child.props.value,
                onClick: () => onChange(child.props.value),
              })
            }
            return child
          })}
    </div>
  )
}

interface AdminTabProps {
  value: string
  icon?: React.ReactNode
  children: React.ReactNode
  active?: boolean
  onClick?: () => void
  className?: string
}

export function AdminTab({ icon, children, active, onClick, className }: AdminTabProps) {
  return (
    <button
      onClick={onClick}
      className={cn(
        "flex items-center gap-2 px-4 py-2.5 text-sm font-medium border-b-2 transition-colors -mb-px",
        active
          ? "border-[#0B7A8F] text-[#0B7A8F]"
          : "border-transparent text-gray-500 hover:text-gray-700",
        className
      )}
    >
      {icon}
      {children}
    </button>
  )
}

