                  </div>
                </div>
                <div className="flex items-start gap-3 p-3 border border-gray-200 rounded-xl hover:border-[#0B7A8F] transition-colors cursor-pointer">
                  <RadioGroupItem value="prazo_especial" id="cond-prazo" className="mt-0.5" />
                  <div>
                    <Label htmlFor="cond-prazo" className="font-medium cursor-pointer">Prazo Especial</Label>
                    <p className="text-xs text-gray-500 mt-0.5">Estende o prazo de pagamento para este cliente</p>
                  </div>
                </div>
              </RadioGroup>
            </div>

            {(novaCondicao.tipoCondicao === "desconto" || novaCondicao.tipoCondicao === "funcoes_pj") && (
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <label className="text-sm font-medium text-gray-700 flex items-center gap-2"><Percent size={14} />Desconto (%)</label>
                  <AdminInput variant="form" type="number" min={0} max={100} value={novaCondicao.desconto} onChange={(e) => setNovaCondicao((p) => ({ ...p, desconto: Number(e.target.value) }))} />
                </div>
                <div className="space-y-2">
                  <label className="text-sm font-medium text-gray-700">Prazo de pagamento (dias)</label>
                  <AdminInput variant="form" type="number" min={1} value={novaCondicao.prazo} onChange={(e) => setNovaCondicao((p) => ({ ...p, prazo: Number(e.target.value) }))} />
                </div>
              </div>
            )}

            {novaCondicao.tipoCondicao === "prazo_especial" && (
              <div className="space-y-2">
                <label className="text-sm font-medium text-gray-700">Prazo de pagamento (dias)</label>
                <AdminInput variant="form" type="number" min={1} value={novaCondicao.prazo} onChange={(e) => setNovaCondicao((p) => ({ ...p, prazo: Number(e.target.value) }))} />
              </div>
            )}

            <div className="space-y-2">
              <label className="text-sm font-medium text-gray-700 flex items-center gap-2"><Calendar size={14} />Vigência da Condição</label>
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1">
                  <span className="text-xs text-gray-500">Data início</span>
                  <AdminInput variant="form" type="date" value={novaCondicao.vigenciaInicio} onChange={(e) => setNovaCondicao((p) => ({ ...p, vigenciaInicio: e.target.value }))} />
                </div>
                <div className="space-y-1">
                  <span className="text-xs text-gray-500">Data fim</span>
                  <AdminInput variant="form" type="date" value={novaCondicao.vigenciaFim} onChange={(e) => setNovaCondicao((p) => ({ ...p, vigenciaFim: e.target.value }))} />
                </div>
              </div>
            </div>

            <div className="p-4 bg-[#0B7A8F]/5 border border-[#0B7A8F]/20 rounded-xl">
              <p className="text-sm font-medium text-[#0B7A8F]">Resumo da Condição</p>
              <ul className="mt-2 space-y-1 text-sm text-gray-600">
                <li>• Tipo: <span className="font-medium">{tipoCondicaoConfig[novaCondicao.tipoCondicao].label}</span></li>
                {novaCondicao.desconto > 0 && <li>• Desconto: <span className="font-medium">{novaCondicao.desconto}%</span></li>}
                <li>• Prazo: <span className="font-medium">{novaCondicao.prazo} dias</span></li>
                {novaCondicao.vigenciaFim && <li>• Válido até: <span className="font-medium">{novaCondicao.vigenciaFim}</span></li>}
              </ul>
            </div>
          </AdminModalBody>
          <AdminModalFooter>
            <AdminButton variant="outline" onClick={handleCancelarCondicao}>Cancelar</AdminButton>
            <AdminButton variant="primary" onClick={handleSalvarCondicao} disabled={!isCondicaoFormValid}>Salvar Condição</AdminButton>
          </AdminModalFooter>
        </AdminModal>
      )}

      {/* ── Modal Tabela de Preços ───────────────────────────────────────────── */}
      {showModalTabelaPrecos && condicaoTabela && (
        <AdminModal onClose={() => setShowModalTabelaPrecos(false)} size="lg">
          <AdminModalHeader
            title="Tabela de Preços"
            subtitle={`Valores de ${condicaoTabela.clienteNome}`}
            onClose={() => setShowModalTabelaPrecos(false)}
          />
          <AdminModalBody>
            <div className="space-y-2">
              <label className="text-sm font-medium text-gray-700">Tipo de Cliente</label>
              <RadioGroup
                value={tabelaPrecos.tipoConta}
                onValueChange={(v) => setTabelaPrecos((p) => ({ ...p, tipoConta: v as "pf" | "pj" }))}
                className="flex gap-4"
              >
                <div className="flex items-center gap-2">
                  <RadioGroupItem value="pf" id="tabela-tipo-pf" />
                  <Label htmlFor="tabela-tipo-pf">Pessoa Física</Label>
                </div>
                <div className="flex items-center gap-2">
                  <RadioGroupItem value="pj" id="tabela-tipo-pj" />
                  <Label htmlFor="tabela-tipo-pj">Pessoa Jurídica</Label>
                </div>
              </RadioGroup>
            </div>
            <TabelaPrecosForm tabela={tabelaPrecos} onChange={setTabelaPrecos} />
          </AdminModalBody>
          <AdminModalFooter>
            <AdminButton variant="outline" onClick={() => setShowModalTabelaPrecos(false)}>Cancelar</AdminButton>
            <AdminButton variant="primary" onClick={() => setShowModalTabelaPrecos(false)}>Salvar</AdminButton>
          </AdminModalFooter>
        </AdminModal>
      )}
    </AdminDashboardLayout>
  )
}

input.content:
"use client"

import { useMemo, useState } from "react"
import { AdminDashboardLayout } from "@/components/admin/admin-dashboard-layout"
import { AdminButton } from "@/components/admin/admin-button"
import { AdminTable, AdminTableSortHeader } from "@/components/admin/admin-table"
import { AdminTabs } from "@/components/admin/admin-tabs"
import { AdminModal, AdminModalHeader, AdminModalBody, AdminModalFooter } from "@/components/admin/admin-modal"
import { AdminInput } from "@/components/admin/admin-input"
import {
  PEDIDOS,
  type Pedido,
  type StatusPedido,
} from "@/lib/mock-pedidos"
import { type ColumnDef } from "@tanstack/react-table"
import {
  Eye,
  CheckCircle2,
  XCircle,
  Copy,
  Search,
  FileText,
  AlertCircle,
  Clock,
  Ban,
  CreditCard,
  History,
  Paperclip,
  RotateCcw,
  Download,
} from "lucide-react"
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select"
import { cn } from "@/lib/utils"

// ─── Helpers ─────────────────────────────────────────────────────────────────

type AbaStatus = "PENDENTE" | "ACEITO" | "NAO_ACEITO" | "CANCELADO"

const ABA_CONFIG: Record<AbaStatus, { label: string; icon: React.ElementType }> = {
  PENDENTE:   { label: "Pendente",    icon: Clock       },
  ACEITO:     { label: "Aceito",      icon: CheckCircle2 },
  NAO_ACEITO: { label: "Não Aceito",  icon: XCircle     },
  CANCELADO:  { label: "Cancelado",   icon: Ban         },
}

const PAGAMENTO_CONFIG: Record<string, { label: string; className: string }> = {
  AGUARDANDO: { label: "Aguardando",  className: "bg-yellow-50 text-yellow-700" },
  PAGO:       { label: "Pago",        className: "bg-green-50 text-green-700"   },
  FALHOU:     { label: "Falhou",      className: "bg-red-50 text-red-600"       },
  ESTORNADO:  { label: "Estornado",   className: "bg-orange-50 text-orange-600" },
  ISENTO:     { label: "Isento",      className: "bg-gray-100 text-gray-500"    },
}

const PRIORIDADE_CONFIG: Record<string, { className: string }> = {
  P1: { className: "bg-red-50 text-red-600"     },
  P2: { className: "bg-orange-50 text-orange-600" },
  P3: { className: "bg-gray-100 text-gray-500"  },
}

const MOTIVOS_REJEICAO = [
  "Pedido duplicado",
  "Cliente desistiu",
  "Agenda indisponível",
  "Endereço incompleto",
  "Sem pagamento confirmado",
  "Outro (descrever)",
]

// ─── Badge pagamento ──────────────────────────────────────────────────────────
function BadgePagamento({ status }: { status: string }) {
  const cfg = PAGAMENTO_CONFIG[status] ?? PAGAMENTO_CONFIG.AGUARDANDO
  return (
    <span className={cn("inline-flex items-center gap-1 text-xs font-medium px-2.5 py-1 rounded-full", cfg.className)}>
      <CreditCard size={11} />
      {cfg.label}
    </span>
  )
}

// ─── Modal Visualizar ─────────────────────────────────────────────────────────
type AbaDetalhe = "dados" | "historico" | "documentos"

function ModalVisualizar({ pedido, onClose }: { pedido: Pedido; onClose: () => void }) {
  const [aba, setAba] = useState<AbaDetalhe>("dados")

  const abas = [
    { id: "dados",      label: "Dados do Pedido", icon: FileText  },
    { id: "historico",  label: "Histórico",        icon: History   },
    { id: "documentos", label: "Documentos",       icon: Paperclip },
  ]

  return (
    <AdminModal onClose={onClose} size="lg">
      <AdminModalHeader
        title={pedido.id}
        subtitle={`${pedido.tipoVistoria} · ${pedido.logradouro}, ${pedido.numero}${pedido.complemento ? ` — ${pedido.complemento}` : ""}`}
        onClose={onClose}
      />
      <AdminModalBody className="!pt-0">
        {/* Abas internas */}
        <div className="-mx-6 px-6 pt-4 border-b border-gray-100 mb-6">
          <div className="flex gap-1">
            {abas.map((a) => {
              const Icon = a.icon
              const active = aba === a.id
              return (
                <button
                  key={a.id}
                  onClick={() => setAba(a.id as AbaDetalhe)}
                  className={cn(
                    "flex items-center gap-2 px-4 py-2.5 text-sm font-medium border-b-2 transition-colors -mb-px",
                    active
                      ? "border-[#0B7A8F] text-[#0B7A8F]"
                      : "border-transparent text-gray-500 hover:text-gray-700"
                  )}
                >
                  <Icon size={14} />
                  {a.label}
                </button>
              )
            })}
          </div>
        </div>

        {/* Aba Dados */}
        {aba === "dados" && (
          <div className="space-y-6">
            {/* Cabeçalho do pedido */}
            <div className="grid grid-cols-3 gap-4 p-4 bg-gray-50 rounded-lg">
              <div>
                <p className="text-xs text-gray-400">ID do Pedido</p>
                <p className="text-sm font-semibold text-gray-900 font-mono">{pedido.id}</p>
              </div>
              <div>
                <p className="text-xs text-gray-400">Data de Criação</p>
                <p className="text-sm font-medium text-gray-700">{pedido.dataCriacao}</p>
              </div>
              <div>
                <p className="text-xs text-gray-400">Canal</p>
                <p className="text-sm font-medium text-gray-700">{pedido.canal}</p>
              </div>
            </div>

            {/* Imóvel */}
            <div>
              <p className="text-xs font-semibold text-gray-400 uppercase tracking-wide mb-3">Imóvel</p>
              <div className="grid grid-cols-2 gap-x-6 gap-y-3">
                <Row label="Endereço" value={`${pedido.logradouro}, ${pedido.numero}${pedido.complemento ? `, ${pedido.complemento}` : ""}`} />
                <Row label="Bairro / Cidade / UF" value={`${pedido.bairro} · ${pedido.cidade} — ${pedido.uf}`} />
                <Row label="CEP" value={pedido.cep} />
                <Row label="Tipo" value={pedido.tipoImovel} />
                <Row label="Área útil" value={`${pedido.areaUtil} m²`} />
                <Row label="Mobília" value={pedido.mobilia} />
                <Row label="Status do imóvel" value={pedido.statusImovel} />
                {pedido.referenciaAcesso && <Row label="Referência / Acesso" value={pedido.referenciaAcesso} cols={2} />}
              </div>
            </div>

            {/* Vistoria */}
            <div>
              <p className="text-xs font-semibold text-gray-400 uppercase tracking-wide mb-3">Vistoria</p>
              <div className="grid grid-cols-2 gap-x-6 gap-y-3">
                <Row label="Tipo" value={pedido.tipoVistoria} />
                <Row label="Data / Hora" value={`${pedido.dataVistoria} às ${pedido.horaVistoria}`} />
                {pedido.janelaToleranciaMins && <Row label="Tolerância" value={`±${pedido.janelaToleranciaMins} min`} />}
                {pedido.observacoes && <Row label="Observações" value={pedido.observacoes} cols={2} />}
              </div>
            </div>

            {/* Cliente / Contato */}
            <div>
              <p className="text-xs font-semibold text-gray-400 uppercase tracking-wide mb-3">Cliente / Contato</p>
              <div className="grid grid-cols-2 gap-x-6 gap-y-3">
                <Row label="Cliente" value={`${pedido.clienteNome} (${pedido.tipoCliente})`} />
                <Row label="Prioridade" value={pedido.prioridade} badge={PRIORIDADE_CONFIG[pedido.prioridade]?.className} />
                <Row label="Contato" value={pedido.contatoNome} />
                <Row label="E-mail" value={pedido.contatoEmail} />
                <Row label="Telefone" value={pedido.contatoTelefone} />
                <Row label="Selo" value={pedido.temSelo ? "Sim — liberado de pré-pagamento" : "Não"} />
              </div>
            </div>

            {/* Financeiro */}
            <div>
              <p className="text-xs font-semibold text-gray-400 uppercase tracking-wide mb-3">Financeiro</p>
              <div className="grid grid-cols-2 gap-x-6 gap-y-3">
                <Row label="Valor" value={pedido.valor} />
                <Row label="Forma de cobrança" value={pedido.formaCobanca} />
                <Row label="Pagamento antecipado" value={pedido.requerPagamentoAntecipado ? "Sim" : "Não"} />
                <Row label="Status pagamento" value={PAGAMENTO_CONFIG[pedido.statusPagamento]?.label ?? pedido.statusPagamento} />
                {pedido.idTransacaoNeofin && <Row label="Transação Neofin" value={pedido.idTransacaoNeofin} />}
              </div>
            </div>

            {/* Envolvidos */}
            {pedido.envolvidos.length > 0 && (
              <div>
                <p className="text-xs font-semibold text-gray-400 uppercase tracking-wide mb-3">Envolvidos</p>
                <div className="space-y-3">
                  {pedido.envolvidos.map((env, i) => (
                    <div key={i} className="p-3 border border-gray-100 rounded-lg space-y-1.5">
                      <div className="flex items-center gap-2">
                        <span className="text-xs font-semibold text-[#0B7A8F] bg-[#0B7A8F]/10 px-2 py-0.5 rounded">{env.tipo}</span>
                        <span className="text-sm font-medium text-gray-800">{env.nome}</span>
                      </div>
                      <div className="flex flex-wrap gap-x-4 gap-y-1 text-xs text-gray-500">
                        <span>{env.cpfCnpj}</span>
                        <span>{env.telefone}</span>
                        <span>{env.email}</span>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {/* Motivo rejeição / cancelamento */}
            {(pedido.motivoRejeicao || pedido.motivoCancelamento) && (
              <div className="p-4 border border-red-100 bg-red-50 rounded-lg">
                <p className="text-xs font-semibold text-red-700 uppercase tracking-wide mb-1">
                  {pedido.motivoRejeicao ? "Motivo da Rejeição" : "Motivo do Cancelamento"}
                </p>
                <p className="text-sm text-red-700">{pedido.motivoRejeicao ?? pedido.motivoCancelamento}</p>
                {pedido.taxaCancelamentoAplicada && (
                  <p className="text-xs text-red-500 mt-1">Taxa de cancelamento aplicada (cancelamento &lt;24h)</p>
                )}
              </div>
            )}
          </div>
        )}

        {/* Aba Histórico */}
        {aba === "historico" && (
          <div className="space-y-3">
            {pedido.historico.map((h, i) => (
              <div key={i} className="flex gap-4">
                <div className="flex flex-col items-center">
                  <div className="h-2.5 w-2.5 rounded-full bg-[#0B7A8F] mt-1 shrink-0" />
                  {i < pedido.historico.length - 1 && <div className="w-px flex-1 bg-gray-100 mt-1" />}
                </div>
                <div className="pb-4">
                  <p className="text-sm font-medium text-gray-800">{h.acao}</p>
                  {h.detalhe && <p className="text-xs text-gray-500 mt-0.5">{h.detalhe}</p>}
                  <p className="text-xs text-gray-400 mt-1">{h.dataHora} · {h.ator}</p>
                </div>
              </div>
            ))}
          </div>
        )}

        {/* Aba Documentos */}
        {aba === "documentos" && (
          <div className="space-y-3">
            <div className="flex items-center justify-between p-4 border border-gray-100 rounded-lg">
              <div className="flex items-center gap-3">
                <div className="h-9 w-9 rounded-lg bg-[#0B7A8F]/10 flex items-center justify-center">
                  <FileText size={16} className="text-[#0B7A8F]" />
                </div>
                <div>
                  <p className="text-sm font-medium text-gray-800">Recibo de Solicitação</p>
                  <p className="text-xs text-gray-400">Recibo-{pedido.id}.pdf · Gerado em {pedido.dataCriacao}</p>
                </div>
              </div>
              <AdminButton variant="outline" size="sm" icon={<Download size={14} />}>
                Baixar
              </AdminButton>
            </div>
            <p className="text-xs text-gray-400 text-center py-2">Outros documentos aparecerão aqui conforme o pedido avança.</p>
          </div>
        )}
      </AdminModalBody>
      <AdminModalFooter>
        <AdminButton variant="outline" onClick={onClose}>Fechar</AdminButton>
        <AdminButton variant="outline" icon={<Download size={15} />} onClick={() => {}}>
          Baixar Recibo
        </AdminButton>
      </AdminModalFooter>
    </AdminModal>
  )
}

// ─── Row helper ───────────────────────────────────────────────────────────────
function Row({ label, value, cols, badge }: { label: string; value: string; cols?: number; badge?: string }) {
  return (
    <div className={cols === 2 ? "col-span-2" : ""}>
      <p className="text-xs text-gray-400">{label}</p>
      {badge ? (
        <span className={cn("inline-flex items-center text-xs font-semibold px-2 py-0.5 rounded mt-0.5", badge)}>{value}</span>
      ) : (
        <p className="text-sm font-medium text-gray-700">{value}</p>
      )}
    </div>
  )
}

// ─── Modal Rejeitar ───────────────────────────────────────────────────────────
function ModalRejeitar({ pedido, onClose, onConfirm }: { pedido: Pedido; onClose: () => void; onConfirm: (motivo: string) => void }) {
  const [motivoSelecionado, setMotivoSelecionado] = useState("")
  const [detalhe, setDetalhe] = useState("")

  const textoFinal = motivoSelecionado === "Outro (descrever)" ? detalhe : `${motivoSelecionado}${detalhe ? ` — ${detalhe}` : ""}`
  const valido = motivoSelecionado !== "" && textoFinal.length >= 10

  return (
    <AdminModal onClose={onClose} size="sm">
      <AdminModalHeader
        title="Rejeitar Pedido"
        subtitle={pedido.id}
        onClose={onClose}
      />
      <AdminModalBody>
        <div className="space-y-4">
          <div className="space-y-2">
            <label className="text-sm font-medium text-gray-700">Motivo da rejeição</label>
            <Select value={motivoSelecionado} onValueChange={setMotivoSelecionado}>
              <SelectTrigger className="h-10">
                <SelectValue placeholder="Selecione o motivo..." />
              </SelectTrigger>
              <SelectContent>
                {MOTIVOS_REJEICAO.map((m) => (
                  <SelectItem key={m} value={m}>{m}</SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>

          <div className="space-y-1.5">
            <label className="text-sm font-medium text-gray-700">
              {motivoSelecionado === "Outro (descrever)" ? "Descreva o motivo" : "Detalhes adicionais"}
              {motivoSelecionado === "Outro (descrever)" && <span className="text-red-500 ml-1">*</span>}
            </label>
            <textarea
              className="w-full h-24 px-3 py-2 text-sm border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-[#0B7A8F]/20 focus:border-[#0B7A8F] resize-none"
              placeholder="Adicione detalhes para o cliente... (mín. 10 caracteres)"
              value={detalhe}
              onChange={(e) => setDetalhe(e.target.value)}
            />
            <p className="text-xs text-gray-400">{textoFinal.length} / 10 caracteres mínimos</p>
          </div>

          <div className="p-3 bg-yellow-50 border border-yellow-100 rounded-lg flex items-start gap-2">
            <AlertCircle size={15} className="text-yellow-600 shrink-0 mt-0.5" />
            <p className="text-xs text-yellow-700">O cliente será notificado com o motivo informado. Esta ação não pode ser desfeita.</p>
          </div>
        </div>
      </AdminModalBody>
      <AdminModalFooter>
        <AdminButton variant="outline" onClick={onClose}>Cancelar</AdminButton>
        <AdminButton variant="danger" onClick={() => onConfirm(textoFinal)} disabled={!valido}>
          Confirmar Rejeição
        </AdminButton>
      </AdminModalFooter>
    </AdminModal>
  )
}

// ─── Modal Replicar ───────────────────────────────────────────────────────────
function ModalReplicar({ pedido, onClose, onConfirm }: { pedido: Pedido; onClose: () => void; onConfirm: () => void }) {
  const [dataVistoria, setDataVistoria] = useState("")
  const [horaVistoria, setHoraVistoria] = useState("")
  const [obs, setObs] = useState(pedido.observacoes ?? "")

  return (
    <AdminModal onClose={onClose} size="sm">
      <AdminModalHeader
        title="Replicar Pedido"
        subtitle={`Baseado em ${pedido.id}`}
        onClose={onClose}
      />
      <AdminModalBody>
        <div className="p-3 bg-[#0B7A8F]/5 border border-[#0B7A8F]/20 rounded-lg space-y-1 text-sm mb-2">
          <p className="font-medium text-[#0B7A8F]">Dados copiados do pedido original</p>
          <p className="text-gray-600"><span className="text-gray-400">Imóvel:</span> {pedido.logradouro}, {pedido.numero}</p>
          <p className="text-gray-600"><span className="text-gray-400">Tipo:</span> {pedido.tipoVistoria}</p>
          <p className="text-gray-600"><span className="text-gray-400">Cliente:</span> {pedido.clienteNome}</p>
        </div>

        <div className="space-y-4">
          <div className="grid grid-cols-2 gap-3">
            <div className="space-y-1.5">
              <label className="text-sm font-medium text-gray-700">Nova data <span className="text-red-500">*</span></label>
              <AdminInput
                variant="form"
                type="date"
                value={dataVistoria}
                onChange={(e) => setDataVistoria(e.target.value)}
              />
            </div>
            <div className="space-y-1.5">
              <label className="text-sm font-medium text-gray-700">Horário <span className="text-red-500">*</span></label>
              <Select value={horaVistoria} onValueChange={setHoraVistoria}>
                <SelectTrigger className="h-10">
                  <SelectValue placeholder="Selecione" />
                </SelectTrigger>
                <SelectContent>
                  {["08:00","09:00","10:00","11:00","13:00","14:00","15:00","16:00","17:00"].map((h) => (
                    <SelectItem key={h} value={h}>{h}</SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
          </div>

          <div className="space-y-1.5">
            <label className="text-sm font-medium text-gray-700">Observações</label>
            <textarea
              className="w-full h-20 px-3 py-2 text-sm border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-[#0B7A8F]/20 focus:border-[#0B7A8F] resize-none"
              value={obs}
              onChange={(e) => setObs(e.target.value)}
            />
          </div>
        </div>
      </AdminModalBody>
      <AdminModalFooter>
        <AdminButton variant="outline" onClick={onClose}>Cancelar</AdminButton>
        <AdminButton
          variant="primary"
          onClick={onConfirm}
          disabled={!dataVistoria || !horaVistoria}
          icon={<RotateCcw size={15} />}
        >
          Criar Novo Pedido
        </AdminButton>
      </AdminModalFooter>
    </AdminModal>
  )
}

// ─── Page ─────────────────────────────────────────────────────────────────────
export default function BackofficeVistoriasPedidosPage() {
