        <div>
          <p className="text-sm font-medium text-gray-800">{row.original.clienteNome}</p>
          <span className="text-xs text-gray-400">{row.original.tipoCliente}</span>
        </div>
      ),
    },
    {
      accessorKey: "logradouro",
      header: "Endereço",
      cell: ({ row }) => (
        <span className="text-sm text-gray-600">
          {row.original.logradouro}, {row.original.numero} — {row.original.cidade}/{row.original.uf}
        </span>
      ),
    },
    {
      accessorKey: "tipoVistoria",
      header: "Tipo",
      cell: ({ row }) => <span className="text-sm text-gray-600">{row.original.tipoVistoria}</span>,
    },
    {
      accessorKey: "valor",
      header: "Valor",
      cell: ({ row }) => <span className="text-sm font-semibold text-gray-800">{row.original.valor}</span>,
    },
    {
      accessorKey: "statusPagamento",
      header: "Pagamento",
      cell: ({ row }) => <BadgePagamento status={row.original.statusPagamento} />,
    },
    {
      accessorKey: "quemAprovou",
      header: "Aprovado por",
      cell: ({ row }) => <span className="text-xs text-gray-400">{row.original.quemAprovou ?? "—"}</span>,
    },
    {
      id: "acoes",
      header: "",
      cell: ({ row }) => (
        <div className="flex justify-end">
          <AdminButton variant="ghost" size="sm" icon={<Eye size={14} />} className="h-8 w-8 p-0" title="Visualizar" onClick={() => setPedidoVisualizar(row.original)} />
        </div>
      ),
    },
  ]

  // ─── Colunas Não Aceito ───────────────────────────────────────────────────
  const colunasNaoAceito: ColumnDef<Pedido>[] = [
    {
      accessorKey: "id",
      header: ({ column }) => <AdminTableSortHeader column={column} label="Pedido" />,
      cell: ({ row }) => <span className="font-mono text-xs text-gray-500">{row.original.id}</span>,
    },
    {
      accessorKey: "clienteNome",
      header: ({ column }) => <AdminTableSortHeader column={column} label="Cliente" />,
      cell: ({ row }) => (
        <div>
          <p className="text-sm font-medium text-gray-800">{row.original.clienteNome}</p>
          <span className="text-xs text-gray-400">{row.original.tipoCliente}</span>
        </div>
      ),
    },
    {
      accessorKey: "logradouro",
      header: "Endereço",
      cell: ({ row }) => (
        <span className="text-sm text-gray-600">
          {row.original.logradouro}, {row.original.numero} — {row.original.cidade}/{row.original.uf}
        </span>
      ),
    },
    {
      accessorKey: "tipoVistoria",
      header: "Tipo",
      cell: ({ row }) => <span className="text-sm text-gray-600">{row.original.tipoVistoria}</span>,
    },
    {
      accessorKey: "motivoRejeicao",
      header: "Motivo",
      cell: ({ row }) => (
        <span className="text-sm text-red-600">{row.original.motivoRejeicao ?? "—"}</span>
      ),
    },
    {
      accessorKey: "quemRejeitou",
      header: "Rejeitado por",
      cell: ({ row }) => <span className="text-xs text-gray-400">{row.original.quemRejeitou ?? "—"}</span>,
    },
    {
      id: "acoes",
      header: "",
      cell: ({ row }) => (
        <div className="flex items-center justify-end gap-1">
          <AdminButton variant="ghost" size="sm" icon={<Eye size={14} />} className="h-8 w-8 p-0" title="Visualizar" onClick={() => setPedidoVisualizar(row.original)} />
          <AdminButton variant="ghost" size="sm" icon={<RotateCcw size={14} />} className="h-8 w-8 p-0 text-[#0B7A8F]" title="Replicar pedido" onClick={() => setPedidoReplicar(row.original)} />
        </div>
      ),
    },
  ]

  // ─── Colunas Cancelado ────────────────────────────────────────────────────
  const colunasCancelado: ColumnDef<Pedido>[] = [
    {
      accessorKey: "id",
      header: ({ column }) => <AdminTableSortHeader column={column} label="Pedido" />,
      cell: ({ row }) => <span className="font-mono text-xs text-gray-500">{row.original.id}</span>,
    },
    {
      accessorKey: "clienteNome",
      header: ({ column }) => <AdminTableSortHeader column={column} label="Cliente" />,
      cell: ({ row }) => (
        <div>
          <p className="text-sm font-medium text-gray-800">{row.original.clienteNome}</p>
          <span className="text-xs text-gray-400">{row.original.tipoCliente}</span>
        </div>
      ),
    },
    {
      accessorKey: "logradouro",
      header: "Endereço",
      cell: ({ row }) => (
        <span className="text-sm text-gray-600">
          {row.original.logradouro}, {row.original.numero} — {row.original.cidade}/{row.original.uf}
        </span>
      ),
    },
    {
      accessorKey: "tipoVistoria",
      header: "Tipo",
      cell: ({ row }) => <span className="text-sm text-gray-600">{row.original.tipoVistoria}</span>,
    },
    {
      accessorKey: "motivoCancelamento",
      header: "Motivo",
      cell: ({ row }) => <span className="text-sm text-gray-600">{row.original.motivoCancelamento ?? "—"}</span>,
    },
    {
      accessorKey: "quemCancelou",
      header: "Cancelado por",
      cell: ({ row }) => <span className="text-xs text-gray-400">{row.original.quemCancelou ?? "—"}</span>,
    },
    {
      id: "taxa",
      header: "Taxa",
      cell: ({ row }) => (
        row.original.taxaCancelamentoAplicada
          ? <span className="text-xs font-medium text-orange-600 bg-orange-50 px-2 py-0.5 rounded">Aplicada</span>
          : <span className="text-xs text-gray-400">—</span>
      ),
    },
    {
      id: "acoes",
      header: "",
      cell: ({ row }) => (
        <div className="flex items-center justify-end gap-1">
          <AdminButton variant="ghost" size="sm" icon={<Eye size={14} />} className="h-8 w-8 p-0" title="Visualizar" onClick={() => setPedidoVisualizar(row.original)} />
          <AdminButton variant="ghost" size="sm" icon={<RotateCcw size={14} />} className="h-8 w-8 p-0 text-[#0B7A8F]" title="Replicar pedido" onClick={() => setPedidoReplicar(row.original)} />
        </div>
      ),
    },
  ]

  const colunasMap: Record<AbaStatus, ColumnDef<Pedido>[]> = {
    PENDENTE:   colunasPendente,
    ACEITO:     colunasAceito,
    NAO_ACEITO: colunasNaoAceito,
    CANCELADO:  colunasCancelado,
  }

  // ─── Aviso pagamento ──────────────────────────────────────────────────────
  const pedidosPFSemPagamento = useMemo(
    () => aba === "PENDENTE"
      ? dadosAba.filter((p) => p.requerPagamentoAntecipado && !p.temSelo && p.statusPagamento === "AGUARDANDO").length
      : 0,
    [aba, dadosAba]
  )

  return (
    <AdminDashboardLayout
      profile="backoffice"
      title="Pedidos de Vistoria"
      breadcrumbs={[
        { label: "Vistorias", href: "/admin/backoffice/vistorias/pedidos" },
        { label: "Pedidos" },
      ]}
    >
      <div className="space-y-4">
        {/* Abas */}
        <AdminTabs value={aba} onChange={(v) => { setAba(v as AbaStatus); setBusca("") }} tabs={abas} />

        {/* Aviso PF sem pagamento */}
        {pedidosPFSemPagamento > 0 && (
          <div className="flex items-center gap-3 px-4 py-3 bg-yellow-50 border border-yellow-100 rounded-lg">
            <AlertCircle size={16} className="text-yellow-600 shrink-0" />
            <p className="text-sm text-yellow-700">
              <span className="font-semibold">{pedidosPFSemPagamento} pedido{pedidosPFSemPagamento > 1 ? "s" : ""}</span>{" "}
              de cliente{pedidosPFSemPagamento > 1 ? "s" : ""} PF aguardando pagamento — aprovação bloqueada até confirmação Neofin.
            </p>
          </div>
        )}

        {/* Busca */}
        <div className="flex items-end gap-3">
          <div className="flex-1 min-w-[250px]">
            <AdminInput
              variant="form"
              placeholder="Buscar por ID, endereço ou cliente..."
              value={busca}
              onChange={(e) => setBusca(e.target.value)}
              icon={<Search size={15} />}
            />
          </div>
          <span className="text-sm text-gray-500 pb-0.5">
            <span className="font-semibold text-gray-800">{dadosAba.length}</span> pedido{dadosAba.length !== 1 ? "s" : ""}
          </span>
        </div>

        {/* Tabela */}
        <AdminTable
          data={dadosAba}
          columns={colunasMap[aba]}
          filterValue={busca}
          showSearch={false}
          emptyMessage={`Nenhum pedido ${ABA_CONFIG[aba].label.toLowerCase()} encontrado.`}
          emptyIcon={<Copy size={32} className="opacity-30" />}
        />
      </div>

      {/* Modais */}
      {pedidoVisualizar && (
        <ModalVisualizar pedido={pedidoVisualizar} onClose={() => setPedidoVisualizar(null)} />
      )}
      {pedidoRejeitar && (
        <ModalRejeitar pedido={pedidoRejeitar} onClose={() => setPedidoRejeitar(null)} onConfirm={handleRejeitar} />
      )}
      {pedidoReplicar && (
        <ModalReplicar pedido={pedidoReplicar} onClose={() => setPedidoReplicar(null)} onConfirm={handleReplicar} />
      )}
    </AdminDashboardLayout>
  )
}

toolUseResult.content:
"use client"

import { useMemo, useState } from "react"
import { AdminDashboardLayout } from "@/components/admin/admin-dashboard-layout"
import { AdminButton } from "@/components/admin/admin-button"
import { AdminTable, AdminTableSortHeader } from "@/components/admin/admin-table"
import { AdminTabs } from "@/components/admin/admin-tabs"
import { AdminModal, AdminModalHeader, AdminModalBody, AdminModalFooter } from "@/components/admin/admin-modal"
import { AdminInput } from "@/components/admin/admin-input"
import {
  PEDIDOS,
  type Pedido,
  type StatusPedido,
} from "@/lib/mock-pedidos"
import { type ColumnDef } from "@tanstack/react-table"
import {
  Eye,
  CheckCircle2,
  XCircle,
  Copy,
  Search,
  FileText,
  AlertCircle,
  Clock,
  Ban,
  CreditCard,
  History,
  Paperclip,
  RotateCcw,
  Download,
} from "lucide-react"
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select"
import { cn } from "@/lib/utils"

// ─── Helpers ─────────────────────────────────────────────────────────────────

type AbaStatus = "PENDENTE" | "ACEITO" | "NAO_ACEITO" | "CANCELADO"

const ABA_CONFIG: Record<AbaStatus, { label: string; icon: React.ElementType }> = {
  PENDENTE:   { label: "Pendente",    icon: Clock       },
  ACEITO:     { label: "Aceito",      icon: CheckCircle2 },
  NAO_ACEITO: { label: "Não Aceito",  icon: XCircle     },
  CANCELADO:  { label: "Cancelado",   icon: Ban         },
}

const PAGAMENTO_CONFIG: Record<string, { label: string; className: string }> = {
  AGUARDANDO: { label: "Aguardando",  className: "bg-yellow-50 text-yellow-700" },
  PAGO:       { label: "Pago",        className: "bg-green-50 text-green-700"   },
  FALHOU:     { label: "Falhou",      className: "bg-red-50 text-red-600"       },
  ESTORNADO:  { label: "Estornado",   className: "bg-orange-50 text-orange-600" },
  ISENTO:     { label: "Isento",      className: "bg-gray-100 text-gray-500"    },
}

const PRIORIDADE_CONFIG: Record<string, { className: string }> = {
  P1: { className: "bg-red-50 text-red-600"     },
  P2: { className: "bg-orange-50 text-orange-600" },
  P3: { className: "bg-gray-100 text-gray-500"  },
}

const MOTIVOS_REJEICAO = [
  "Pedido duplicado",
  "Cliente desistiu",
  "Agenda indisponível",
  "Endereço incompleto",
  "Sem pagamento confirmado",
  "Outro (descrever)",
]

// ─── Badge pagamento ──────────────────────────────────────────────────────────
function BadgePagamento({ status }: { status: string }) {
  const cfg = PAGAMENTO_CONFIG[status] ?? PAGAMENTO_CONFIG.AGUARDANDO
  return (
    <span className={cn("inline-flex items-center gap-1 text-xs font-medium px-2.5 py-1 rounded-full", cfg.className)}>
      <CreditCard size={11} />
      {cfg.label}
    </span>
  )
}

// ─── Modal Visualizar ─────────────────────────────────────────────────────────
type AbaDetalhe = "dados" | "historico" | "documentos"

function ModalVisualizar({ pedido, onClose }: { pedido: Pedido; onClose: () => void }) {
  const [aba, setAba] = useState<AbaDetalhe>("dados")

  const abas = [
    { id: "dados",      label: "Dados do Pedido", icon: FileText  },
    { id: "historico",  label: "Histórico",        icon: History   },
    { id: "documentos", label: "Documentos",       icon: Paperclip },
  ]

  return (
    <AdminModal onClose={onClose} size="lg">
      <AdminModalHeader
        title={pedido.id}
        subtitle={`${pedido.tipoVistoria} · ${pedido.logradouro}, ${pedido.numero}${pedido.complemento ? ` — ${pedido.complemento}` : ""}`}
        onClose={onClose}
      />
      <AdminModalBody className="!pt-0">
        {/* Abas internas */}
        <div className="-mx-6 px-6 pt-4 border-b border-gray-100 mb-6">
          <div className="flex gap-1">
            {abas.map((a) => {
              const Icon = a.icon
              const active = aba === a.id
              return (
                <button
                  key={a.id}
                  onClick={() => setAba(a.id as AbaDetalhe)}
                  className={cn(
                    "flex items-center gap-2 px-4 py-2.5 text-sm font-medium border-b-2 transition-colors -mb-px",
                    active
                      ? "border-[#0B7A8F] text-[#0B7A8F]"
                      : "border-transparent text-gray-500 hover:text-gray-700"
                  )}
                >
                  <Icon size={14} />
                  {a.label}
                </button>
              )
            })}
          </div>
        </div>

        {/* Aba Dados */}
        {aba === "dados" && (
          <div className="space-y-6">
            {/* Cabeçalho do pedido */}
            <div className="grid grid-cols-3 gap-4 p-4 bg-gray-50 rounded-lg">
              <div>
                <p className="text-xs text-gray-400">ID do Pedido</p>
                <p className="text-sm font-semibold text-gray-900 font-mono">{pedido.id}</p>
              </div>
              <div>
                <p className="text-xs text-gray-400">Data de Criação</p>
                <p className="text-sm font-medium text-gray-700">{pedido.dataCriacao}</p>
              </div>
              <div>
                <p className="text-xs text-gray-400">Canal</p>
                <p className="text-sm font-medium text-gray-700">{pedido.canal}</p>
              </div>
            </div>

            {/* Imóvel */}
            <div>
              <p className="text-xs font-semibold text-gray-400 uppercase tracking-wide mb-3">Imóvel</p>
              <div className="grid grid-cols-2 gap-x-6 gap-y-3">
                <Row label="Endereço" value={`${pedido.logradouro}, ${pedido.numero}${pedido.complemento ? `, ${pedido.complemento}` : ""}`} />
                <Row label="Bairro / Cidade / UF" value={`${pedido.bairro} · ${pedido.cidade} — ${pedido.uf}`} />
                <Row label="CEP" value={pedido.cep} />
                <Row label="Tipo" value={pedido.tipoImovel} />
                <Row label="Área útil" value={`${pedido.areaUtil} m²`} />
                <Row label="Mobília" value={pedido.mobilia} />
                <Row label="Status do imóvel" value={pedido.statusImovel} />
                {pedido.referenciaAcesso && <Row label="Referência / Acesso" value={pedido.referenciaAcesso} cols={2} />}
              </div>
            </div>

            {/* Vistoria */}
            <div>
              <p className="text-xs font-semibold text-gray-400 uppercase tracking-wide mb-3">Vistoria</p>
              <div className="grid grid-cols-2 gap-x-6 gap-y-3">
                <Row label="Tipo" value={pedido.tipoVistoria} />
                <Row label="Data / Hora" value={`${pedido.dataVistoria} às ${pedido.horaVistoria}`} />
                {pedido.janelaToleranciaMins && <Row label="Tolerância" value={`±${pedido.janelaToleranciaMins} min`} />}
                {pedido.observacoes && <Row label="Observações" value={pedido.observacoes} cols={2} />}
              </div>
            </div>

            {/* Cliente / Contato */}
