                <Row label="Cliente" value={`${pedido.clienteNome} (${pedido.tipoCliente})`} />
                <Row label="Prioridade" value={pedido.prioridade} badge={PRIORIDADE_CONFIG[pedido.prioridade]?.className} />
                <Row label="Contato" value={pedido.contatoNome} />
                <Row label="E-mail" value={pedido.contatoEmail} />
                <Row label="Telefone" value={pedido.contatoTelefone} />
                <Row label="Selo" value={pedido.temSelo ? "Sim — liberado de pré-pagamento" : "Não"} />
              </div>
            </div>

            {/* Financeiro */}
            <div>
              <p className="text-xs font-semibold text-gray-400 uppercase tracking-wide mb-3">Financeiro</p>
              <div className="grid grid-cols-2 gap-x-6 gap-y-3">
                <Row label="Valor" value={pedido.valor} />
                <Row label="Forma de cobrança" value={pedido.formaCobanca} />
                <Row label="Pagamento antecipado" value={pedido.requerPagamentoAntecipado ? "Sim" : "Não"} />
                <Row label="Status pagamento" value={PAGAMENTO_CONFIG[pedido.statusPagamento]?.label ?? pedido.statusPagamento} />
                {pedido.idTransacaoNeofin && <Row label="Transação Neofin" value={pedido.idTransacaoNeofin} />}
              </div>
            </div>

            {/* Envolvidos */}
            {pedido.envolvidos.length > 0 && (
              <div>
                <p className="text-xs font-semibold text-gray-400 uppercase tracking-wide mb-3">Envolvidos</p>
                <div className="space-y-3">
                  {pedido.envolvidos.map((env, i) => (
