        {/* Aba Histórico */}
        {aba === "historico" && (
          <div className="space-y-3">
            {pedido.historico.map((h, i) => (
              <div key={i} className="flex gap-4">
                <div className="flex flex-col items-center">
                  <div className="h-2.5 w-2.5 rounded-full bg-[#0B7A8F] mt-1 shrink-0" />
                  {i < pedido.historico.length - 1 && <div className="w-px flex-1 bg-gray-100 mt-1" />}
                </div>
                <div className="pb-4">
                  <p className="text-sm font-medium text-gray-800">{h.acao}</p>
                  {h.detalhe && <p className="text-xs text-gray-500 mt-0.5">{h.detalhe}</p>}
                  <p className="text-xs text-gray-400 mt-1">{h.dataHora} · {h.ator}</p>
                </div>
              </div>
            ))}
          </div>
        )}

        {/* Aba Documentos */}
        {aba === "documentos" && (
          <div className="space-y-3">
            <div className="flex items-center justify-between p-4 border border-gray-100 rounded-lg">
              <div className="flex items-center gap-3">
                <div className="h-9 w-9 rounded-lg bg-[#0B7A8F]/10 flex items-center justify-center">
                  <FileText size={16} className="text-[#0B7A8F]" />
                </div>
                <div>
                  <p className="text-sm font-medium text-gray-800">Recibo de Solicitação</p>
                  <p className="text-xs text-gray-400">Recibo-{pedido.id}.pdf · Gerado em {pedido.dataCriacao}</p>
                </div>
              </div>
              <AdminButton variant="outline" size="sm" icon={<Download size={14} />}>
                Baixar
              </AdminButton>
            </div>
            <p className="text-xs text-gray-400 text-center py-2">Outros documentos aparecerão aqui conforme o pedido avança.</p>
          </div>
        )}
      </AdminModalBody>
      <AdminModalFooter>
        <AdminButton variant="outline" onClick={onClose}>Fechar</AdminButton>
        <AdminButton variant="outline" icon={<Download size={15} />} onClick={() => {}}>
          Baixar Recibo
        </AdminButton>
      </AdminModalFooter>
    </AdminModal>
  )
}

// ─── Row helper ───────────────────────────────────────────────────────────────
function Row({ label, value, cols, badge }: { label: string; value: string; cols?: number; badge?: string }) {
  return (
    <div className={cols === 2 ? "col-span-2" : ""}>
      <p className="text-xs text-gray-400">{label}</p>
      {badge ? (
        <span className={cn("inline-flex items-center text-xs font-semibold px-2 py-0.5 rounded mt-0.5", badge)}>{value}</span>
      ) : (
        <p className="text-sm font-medium text-gray-700">{value}</p>
      )}
    </div>
  )
}

// ─── Modal Rejeitar ───────────────────────────────────────────────────────────
function ModalRejeitar({ pedido, onClose, onConfirm }: { pedido: Pedido; onClose: () => void; onConfirm: (motivo: string) => void }) {
  const [motivoSelecionado, setMotivoSelecionado] = useState("")
  const [detalhe, setDetalhe] = useState("")

  const textoFinal = motivoSelecionado === "Outro (descrever)" ? detalhe : `${motivoSelecionado}${detalhe ? ` — ${detalhe}` : ""}`
  const valido = motivoSelecionado !== "" && textoFinal.length >= 10

  return (
    <AdminModal onClose={onClose} size="sm">
      <AdminModalHeader
        title="Rejeitar Pedido"
        subtitle={pedido.id}
        onClose={onClose}
      />
      <AdminModalBody>
        <div className="space-y-4">
          <div className="space-y-2">
            <label className="text-sm font-medium text-gray-700">Motivo da rejeição</label>
            <Select value={motivoSelecionado} onValueChange={setMotivoSelecionado}>
              <SelectTrigger className="h-10">
                <SelectValue placeholder="Selecione o motivo..." />
              </SelectTrigger>
              <SelectContent>
                {MOTIVOS_REJEICAO.map((m) => (
                  <SelectItem key={m} value={m}>{m}</SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>

          <div className="space-y-1.5">
            <label className="text-sm font-medium text-gray-700">
              {motivoSelecionado === "Outro (descrever)" ? "Descreva o motivo" : "Detalhes adicionais"}
              {motivoSelecionado === "Outro (descrever)" && <span className="text-red-500 ml-1">*</span>}
            </label>
            <textarea
              className="w-full h-24 px-3 py-2 text-sm border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-[#0B7A8F]/20 focus:border-[#0B7A8F] resize-none"
              placeholder="Adicione detalhes para o cliente... (mín. 10 caracteres)"
              value={detalhe}
              onChange={(e) => setDetalhe(e.target.value)}
            />
            <p className="text-xs text-gray-400">{textoFinal.length} / 10 caracteres mínimos</p>
          </div>

          <div className="p-3 bg-yellow-50 border border-yellow-100 rounded-lg flex items-start gap-2">
            <AlertCircle size={15} className="text-yellow-600 shrink-0 mt-0.5" />
            <p className="text-xs text-yellow-700">O cliente será notificado com o motivo informado. Esta ação não pode ser desfeita.</p>
          </div>
        </div>
      </AdminModalBody>
      <AdminModalFooter>
        <AdminButton variant="outline" onClick={onClose}>Cancelar</AdminButton>
        <AdminButton variant="danger" onClick={() => onConfirm(textoFinal)} disabled={!valido}>
          Confirmar Rejeição
        </AdminButton>
      </AdminModalFooter>
    </AdminModal>
  )
}

// ─── Modal Replicar ───────────────────────────────────────────────────────────
function ModalReplicar({ pedido, onClose, onConfirm }: { pedido: Pedido; onClose: () => void; onConfirm: () => void }) {
  const [dataVistoria, setDataVistoria] = useState("")
  const [horaVistoria, setHoraVistoria] = useState("")
  const [obs, setObs] = useState(pedido.observacoes ?? "")

  return (
    <AdminModal onClose={onClose} size="sm">
      <AdminModalHeader
        title="Replicar Pedido"
        subtitle={`Baseado em ${pedido.id}`}
        onClose={onClose}
      />
      <AdminModalBody>
        <div className="p-3 bg-[#0B7A8F]/5 border border-[#0B7A8F]/20 rounded-lg space-y-1 text-sm mb-2">
          <p className="font-medium text-[#0B7A8F]">Dados copiados do pedido original</p>
          <p className="text-gray-600"><span className="text-gray-400">Imóvel:</span> {pedido.logradouro}, {pedido.numero}</p>
          <p className="text-gray-600"><span className="text-gray-400">Tipo:</span> {pedido.tipoVistoria}</p>
          <p className="text-gray-600"><span className="text-gray-400">Cliente:</span> {pedido.clienteNome}</p>
        </div>

        <div className="space-y-4">
          <div className="grid grid-cols-2 gap-3">
            <div className="space-y-1.5">
              <label className="text-sm font-medium text-gray-700">Nova data <span className="text-red-500">*</span></label>
              <AdminInput
                variant="form"
                type="date"
                value={dataVistoria}
                onChange={(e) => setDataVistoria(e.target.value)}
              />
            </div>
            <div className="space-y-1.5">
              <label className="text-sm font-medium text-gray-700">Horário <span className="text-red-500">*</span></label>
              <Select value={horaVistoria} onValueChange={setHoraVistoria}>
                <SelectTrigger className="h-10">
                  <SelectValue placeholder="Selecione" />
                </SelectTrigger>
                <SelectContent>
                  {["08:00","09:00","10:00","11:00","13:00","14:00","15:00","16:00","17:00"].map((h) => (
                    <SelectItem key={h} value={h}>{h}</SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
          </div>

          <div className="space-y-1.5">
            <label className="text-sm font-medium text-gray-700">Observações</label>
            <textarea
              className="w-full h-20 px-3 py-2 text-sm border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-[#0B7A8F]/20 focus:border-[#0B7A8F] resize-none"
              value={obs}
              onChange={(e) => setObs(e.target.value)}
            />
          </div>
        </div>
      </AdminModalBody>
      <AdminModalFooter>
        <AdminButton variant="outline" onClick={onClose}>Cancelar</AdminButton>
        <AdminButton
          variant="primary"
          onClick={onConfirm}
          disabled={!dataVistoria || !horaVistoria}
          icon={<RotateCcw size={15} />}
        >
          Criar Novo Pedido
        </AdminButton>
      </AdminModalFooter>
    </AdminModal>
  )
}

