      header: "Endereço",
      cell: ({ row }) => (
        <div>
          <p className="text-sm text-gray-700">{row.original.endereco}{row.original.complemento ? `, ${row.original.complemento}` : ""}</p>
          <p className="text-xs text-gray-400">{row.original.cidade}/{row.original.uf}</p>
        </div>
      ),
    },
    {
      accessorKey: "tipo",
      header: "Tipo",
      cell: ({ row }) => <span className="text-sm text-gray-500">{row.original.tipo}</span>,
    },
    {
      accessorKey: "vistoriadorNome",
      header: "Vistoriador",
      cell: ({ row }) => (
        <div className="flex items-center gap-2">
          <div className="h-7 w-7 rounded-full bg-[#0B7A8F]/10 flex items-center justify-center shrink-0">
            <User size={13} className="text-[#0B7A8F]" />
          </div>
          <div>
            <p className="text-sm font-medium text-gray-800">{row.original.vistoriadorNome}</p>
            <p className="text-xs text-gray-400">{row.original.vistoriadorNivel}</p>
          </div>
        </div>
      ),
    },
    {
      accessorKey: "faseAtual",
      header: "Fase",
      cell: ({ row }) => <BadgeFase fase={row.original.faseAtual} />,
    },
    {
      accessorKey: "semUpdateHaMins",
      header: ({ column }) => <AdminTableSortHeader column={column} label="Última atualização" />,
      cell: ({ row }) => (
        <div className="space-y-1">
          <div className="flex items-center gap-1 text-xs text-gray-400">
            <Clock size={11} />
            <TempoRelativo mins={row.original.semUpdateHaMins} />
          </div>
          <BadgeAlerta mins={row.original.semUpdateHaMins} />
        </div>
      ),
    },
    {
      id: "acoes",
      header: "",
      cell: ({ row }) => (
        <div className="flex justify-end">
          <AdminButton
            variant="ghost"
            size="sm"
            icon={<Eye size={14} />}
            className="h-8 w-8 p-0"
            title="Ver detalhes"
            onClick={() => onVer(row.original)}
          />
        </div>
      ),
    },
  ]
}

// ─── Page ─────────────────────────────────────────────────────────────────────
export default function VistoriasAndamentoPage() {
  const router = useRouter()
  const [busca, setBusca] = useState("")
  const [filtroFase, setFiltroFase] = useState("all")
  const [filtroVistoriador, setFiltroVistoriador] = useState("all")
  const [filtroSomenteAlerta, setFiltroSomenteAlerta] = useState(false)

  const vistoriadores = useMemo(
    () => Array.from(new Set(VISTORIAS_ANDAMENTO.map((v) => v.vistoriadorNome))).sort(),
    []
  )

  const dados = useMemo(() => {
    const termo = busca.toLowerCase()
    return VISTORIAS_ANDAMENTO.filter((v) => {
      const matchBusca =
        !termo ||
        [v.id, v.endereco, v.clienteNome, v.vistoriadorNome, v.cidade].some((s) =>
          s.toLowerCase().includes(termo)
        )
      const matchFase = filtroFase === "all" || v.faseAtual === filtroFase
      const matchVistoriador = filtroVistoriador === "all" || v.vistoriadorNome === filtroVistoriador
      const matchAlerta = !filtroSomenteAlerta || v.temAlerta
      return matchBusca && matchFase && matchVistoriador && matchAlerta
    })
  }, [busca, filtroFase, filtroVistoriador, filtroSomenteAlerta])

  const totalAlertas = useMemo(() => VISTORIAS_ANDAMENTO.filter((v) => v.temAlerta).length, [])

  const columns = useMemo(
    () => buildColumns((v) => router.push(`/admin/cliente/vistorias/andamento/${v.id}`)),
    [router]
  )

  return (
    <AdminDashboardLayout
      profile="cliente"
      title="Vistorias em Andamento"
      breadcrumbs={[{ label: "Vistorias", href: "/admin/cliente/vistorias/andamento" }]}
    >
      <div className="space-y-4">
        {/* Alerta geral */}
        {totalAlertas > 0 && (
          <div className="flex items-center gap-3 px-4 py-3 bg-orange-50 border border-orange-100 rounded-lg">
            <AlertTriangle size={16} className="text-orange-500 shrink-0" />
            <p className="text-sm text-orange-700">
              <span className="font-semibold">{totalAlertas} vistoria{totalAlertas > 1 ? "s" : ""}</span>{" "}
              sem atualização há mais de 30 minutos.
            </p>
            <button
              onClick={() => setFiltroSomenteAlerta(true)}
              className="ml-auto text-xs font-semibold text-orange-600 hover:underline"
            >
              Ver somente alertas
            </button>
          </div>
        )}

        {/* Filtros */}
        <div className="flex flex-wrap items-end gap-3">
          <div className="flex-1 min-w-[200px]">
            <AdminInput
              variant="form"
              placeholder="Buscar por endereço, cliente ou código..."
              value={busca}
              onChange={(e) => setBusca(e.target.value)}
              icon={<Search size={15} />}
            />
          </div>

          <div className="flex flex-col gap-1">
            <label className="text-xs font-medium text-gray-500">Fase</label>
            <Select value={filtroFase} onValueChange={setFiltroFase}>
              <SelectTrigger className="h-10 w-48 px-3">
                <SelectValue placeholder="Todas as fases" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="all">Todas as fases</SelectItem>
                {FASES_ORDERED.map((f) => (
                  <SelectItem key={f} value={f}>{f}</SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>

          <div className="flex flex-col gap-1">
            <label className="text-xs font-medium text-gray-500">Vistoriador</label>
            <Select value={filtroVistoriador} onValueChange={setFiltroVistoriador}>
              <SelectTrigger className="h-10 w-44 px-3">
                <SelectValue placeholder="Todos" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="all">Todos</SelectItem>
                {vistoriadores.map((v) => (
                  <SelectItem key={v} value={v}>{v}</SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>

          <div className="flex flex-col gap-1">
            <label className="text-xs font-medium text-gray-500">Alertas</label>
            <button
              onClick={() => setFiltroSomenteAlerta((v) => !v)}
              className={cn(
                "h-10 px-4 rounded-lg text-sm font-medium border transition-colors",
                filtroSomenteAlerta
                  ? "bg-orange-50 border-orange-200 text-orange-700"
                  : "bg-white border-gray-200 text-gray-500 hover:bg-gray-50"
              )}
            >
              <span className="flex items-center gap-2">
                <AlertTriangle size={14} />
                Somente alertas
              </span>
            </button>
          </div>

          <div className="pb-0.5">
            <span className="text-sm text-gray-500">
              <span className="font-semibold text-gray-800">{dados.length}</span> vistoria{dados.length !== 1 ? "s" : ""}
            </span>
          </div>
        </div>

        {/* Tabela */}
        <AdminTable
          data={dados}
          columns={columns}
          filterValue={busca}
          showSearch={false}
          emptyMessage="Nenhuma vistoria em andamento encontrada."
          emptyIcon={<Clock size={32} className="opacity-30" />}
        />
      </div>
    </AdminDashboardLayout>
  )
}

