"use client"

import { useMemo } from "react"
import Link from "next/link"
import { AdminDashboardLayout } from "@/components/admin/admin-dashboard-layout"
import { AdminButton } from "@/components/admin/admin-button"
import { AdminTable, AdminTableSortHeader } from "@/components/admin/admin-table"
import { vistorias, ETAPAS, type Vistoria } from "@/lib/mock-vistorias"
import { type ColumnDef } from "@tanstack/react-table"
import { Eye, Download, Check } from "lucide-react"

const columns: ColumnDef<Vistoria, unknown>[] = [
  {
    accessorKey: "id",
    header: ({ column }) => <AdminTableSortHeader column={column} label="Código" />,
    cell: ({ row }) => (
      <span className="font-mono text-xs text-gray-500">{row.original.id}</span>
    ),
  },
  {
    accessorKey: "endereco",
    header: "Endereço",
    cell: ({ row }) => (
      <span className="text-sm text-gray-700">{row.original.endereco}</span>
    ),
  },
  {
    accessorKey: "tipo",
    header: "Tipo",
    cell: ({ row }) => (
      <span className="text-sm text-gray-500">{row.original.tipo}</span>
    ),
  },
  {
    accessorKey: "data",
    header: ({ column }) => <AdminTableSortHeader column={column} label="Data" />,
    cell: ({ row }) => (
      <span className="text-sm text-gray-500">{row.original.data}</span>
    ),
  },
  {
    id: "etapa",
    header: "Progresso",
    cell: ({ row }) => {
      const v = row.original
      const pct = Math.round((v.etapa / (ETAPAS.length - 1)) * 100)
      return (
        <div className="flex items-center gap-2 min-w-[120px]">
          <div className="flex-1 h-1.5 bg-gray-100 rounded-full overflow-hidden">
            <div className="h-full bg-[#0B7A8F] rounded-full transition-all" style={{ width: `${pct}%` }} />
          </div>
          <span className="text-xs text-gray-400 w-8 text-right">{pct}%</span>
        </div>
      )
    },
  },
  {
    id: "status",
    header: "Status",
    cell: ({ row }) => (
      <span className={`px-2.5 py-1 rounded-full text-xs font-semibold ${row.original.statusColor}`}>
        {row.original.status}
      </span>
    ),
