      <div className="flex items-center gap-1 justify-end">
        <Link href={`/admin/cliente/vistorias/${row.original.id}`}>
          <AdminButton variant="ghost" size="sm" icon={<Eye size={14} />} className="h-8 w-8 p-0" title="Ver" />
        </Link>
        {row.original.temRelatorio && (
          <AdminButton variant="ghost" size="sm" icon={<Download size={14} />} className="h-8 w-8 p-0 text-[#0B7A8F]" title="Baixar" />
        )}
      </div>
    ),
  },
]

export default function VistoriasAndamentoPage() {
  const data = useMemo(() => vistorias.filter((v) => v.status === "Em andamento"), [])

  return (
    <AdminDashboardLayout
      profile="cliente"
      title="Vistorias em Andamento"
      breadcrumbs={[
        { label: "Vistorias", href: "/admin/cliente/vistorias/andamento" },
      ]}
    >
      <AdminTable
        data={data}
        columns={columns}
        searchPlaceholder="Buscar por código ou endereço..."
        emptyMessage="Nenhuma vistoria em andamento no momento."
      />
    </AdminDashboardLayout>
  )
}

