"use client"

import { useMemo, useState } from "react"
import Link from "next/link"
import { AdminDashboardLayout } from "@/components/admin/admin-dashboard-layout"
import { AdminButton } from "@/components/admin/admin-button"
import { AdminTable } from "@/components/admin/admin-table"
import { AdminModal, AdminModalHeader, AdminModalBody, AdminModalFooter } from "@/components/admin/admin-modal"
import { AdminInput } from "@/components/admin/admin-input"
import { vistorias, type Vistoria } from "@/lib/mock-vistorias"
import { type ColumnDef } from "@tanstack/react-table"
import { Eye, Plus, CheckCircle2, Copy, MapPin, FileText, Calendar, Search } from "lucide-react"
import { RadioGroup, RadioGroupItem } from "@/components/ui/radio-group"
import { Label } from "@/components/ui/label"
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select"

const TIPOS_VISTORIA = ["Entrada", "Saída", "Conferência", "Rescisão"] as const

function gerarCodigo() {
  const ano = new Date().getFullYear()
  const num = Math.floor(1000 + Math.random() * 9000)
  return `V-${ano}-${num}`
}

const columns: ColumnDef<Vistoria, unknown>[] = [
  {
    accessorKey: "id",
    header: "Código",
    cell: ({ row }) => (
      <span className="font-mono text-xs text-gray-500">{row.original.id}</span>
    ),
  },
  {
    accessorKey: "endereco",
    header: "Endereço",
    cell: ({ row }) => (
      <span className="text-sm text-gray-700">{row.original.endereco}</span>
    ),
  },
  {
    accessorKey: "tipo",
    header: "Tipo",
    cell: ({ row }) => (
      <span className="text-sm text-gray-500">{row.original.tipo}</span>
    ),
  },
  {
    id: "status",
    header: "Status",
    cell: () => (
      <span className="px-2.5 py-1 rounded-full text-xs font-semibold text-yellow-700 bg-yellow-50">
        Aguardando
      </span>
    ),
  },
  {
    id: "acoes",
    header: "",
    cell: ({ row }) => (
      <Link href={`/admin/cliente/vistorias/${row.original.id}`}>
        <AdminButton variant="ghost" size="sm" icon={<Eye size={14} />} className="h-8 w-8 p-0" title="Ver" />
      </Link>
    ),
  },
]

export default function VistoriasPedidosPage() {
  const data = useMemo(() => vistorias.filter((v) => v.status === "Pedido"), [])
  const [searchValue, setSearchValue] = useState("")

  // Modal
  const [showModal, setShowModal] = useState(false)
  const [etapa, setEtapa] = useState<"formulario" | "sucesso">("formulario")
  const [codigoGerado, setCodigoGerado] = useState("")
  const [copiado, setCopiado] = useState(false)

  // Campos
  const [endereco, setEndereco] = useState("")
  const [complemento, setComplemento] = useState("")
  const [cidade, setCidade] = useState("")
  const [tipo, setTipo] = useState("")
  const [dataVistoria, setDataVistoria] = useState("")
  const [hora, setHora] = useState("")
  const [obs, setObs] = useState("")

  const formValido = !!(endereco && cidade && tipo && dataVistoria && hora)

  function abrirModal() {
    setEtapa("formulario")
    setCodigoGerado("")
    setEndereco(""); setComplemento(""); setCidade("")
    setTipo(""); setDataVistoria(""); setHora(""); setObs("")
    setShowModal(true)
  }

  function solicitar() {
    setCodigoGerado(gerarCodigo())
    setEtapa("sucesso")
  }

  function copiarCodigo() {
    navigator.clipboard.writeText(codigoGerado)
    setCopiado(true)
    setTimeout(() => setCopiado(false), 2000)
  }

  return (
    <AdminDashboardLayout
      profile="cliente"
      title="Vistorias Solicitadas"
      breadcrumbs={[{ label: "Vistorias", href: "/admin/cliente/vistorias/pedidos" }]}
    >
      <div className="space-y-4">
        {/* Busca + Novo Pedido na mesma linha */}
        <div className="flex flex-wrap items-end gap-3">
          <div className="flex-1 min-w-[250px]">
            <AdminInput
              variant="form"
              placeholder="Buscar por código ou endereço..."
              value={searchValue}
              onChange={(e) => setSearchValue(e.target.value)}
              icon={<Search size={15} />}
            />
          </div>
          <div>
            <AdminButton variant="primary" icon={<Plus size={16} />} onClick={abrirModal}>
              Nova Vistoria
            </AdminButton>
          </div>
        </div>

        {/* Tabela sem search interno */}
        <AdminTable
          data={data}
          columns={columns}
          filterValue={searchValue}
          onFilterChange={setSearchValue}
          showSearch={false}
          emptyMessage="Nenhuma vistoria solicitada aguardando agendamento."
        />
      </div>

      {showModal && (
        <AdminModal onClose={() => setShowModal(false)} size="sm">
          {etapa === "formulario" ? (
            <>
              <AdminModalHeader
                title="Solicitar Nova Vistoria"
                subtitle="Preencha os dados para registrar sua solicitação"
                onClose={() => setShowModal(false)}
              />
              <AdminModalBody>
                {/* Endereço */}
                <div className="space-y-3">
                  <p className="text-xs font-semibold text-gray-500 flex items-center gap-1.5 uppercase tracking-wide">
                    <MapPin size={13} className="text-[#0B7A8F]" /> Endereço do Imóvel
                  </p>
                  <AdminInput
                    variant="form"
                    label="Endereço"
                    placeholder="Rua, número..."
                    value={endereco}
                    onChange={(e) => setEndereco(e.target.value)}
                  />
                  <AdminInput
                    variant="form"
                    label="Complemento"
                    placeholder="Apto, bloco... (opcional)"
                    value={complemento}
                    onChange={(e) => setComplemento(e.target.value)}
                  />
                  <AdminInput
                    variant="form"
                    label="Cidade / UF"
                    placeholder="São Paulo, SP"
                    value={cidade}
                    onChange={(e) => setCidade(e.target.value)}
                  />
                </div>

                {/* Tipo */}
                <div className="space-y-3">
                  <p className="text-xs font-semibold text-gray-500 flex items-center gap-1.5 uppercase tracking-wide">
